SELECT COUNT(*)
FROM project_info p
WHERE p.del_flag = 0


    AND (p.leader_id = #{userId} OR EXISTS (
        SELECT 1 FROM project_member pm 
        WHERE pm.project_id = p.id AND pm.user_id = #{userId} AND pm.del_flag = 0
    ))




        AND p.project_name LIKE CONCAT('%', #{requestDTO.searchText}, '%')


        AND p.status = #{requestDTO.status}


        AND p.leader_id = #{requestDTO.leaderId}

mapper.update:
UPDATE project_info
SET balance = balance - #{amount}, 
    update_time = NOW()
WHERE id = #{projectId} 
AND balance >= #{amount}
AND del_flag = 0
